import { createWeb3Modal, defaultWagmiConfig } from 'https://esm.sh/@web3modal/wagmi@4';
import { mainnet } from 'https://esm.sh/viem@1/chains';

const projectId = 'YOUR_WALLETCONNECT_PROJECT_ID';
const metadata = { name: 'FlatFinder', description: 'Find your next flat', url: window.location.origin, icons: ['/icons/logo.png'] };
const chains = [mainnet];
const config = defaultWagmiConfig({ chains, projectId, metadata });
export const modal = createWeb3Modal({ wagmiConfig: config, projectId, chains });
